if var ri = i._rope, _rope.isValid(ri) {
  if preferEnd {
    guard i.utf8Offset > 0,
          i._chunkIndex.utf8Offset == 0,
          !i._chunkIndex.isUTF16TrailingSurrogate else {
      return i
    }
    _rope.formIndex(before: &ri)
    let length = _rope[ri].utf8Count
    let ci = _Chunk.Index(utf8Offset: length)
    var j = Index(baseUTF8Offset: i.utf8Offset - length, _rope: ri, chunk: ci)
    j._flags = i._flags
    return j
  }
  guard i.utf8Offset < _utf8Count,
        i._chunkIndex.utf8Offset == _rope[ri].utf8Count else {
    return i
  }
  _rope.formIndex(after: &ri)
  let ci = _Chunk.Index(utf8Offset: 0)
  var j = Index(baseUTF8Offset: i.utf8Offset, _rope: ri, chunk: ci)
  j._flags = i._flags
  return j
}

if controlMessage.type == IPV6_TCLASS {
    if let data = controlMessage.data {
        let readValue = ControlMessageParser._readCInt(data: data)
        self.ecnValue = .init(receivedValue: readValue)
    }
} else if controlMessage.type == Posix.IPV6_PKTINFO {
    if let data = controlMessage.data {
        let info = data.load(as: in6_pktinfo.self)
        var addr = sockaddr_in6()
        addr.sin6_family = sa_family_t(NIOBSDSocket.AddressFamily.inet6.rawValue)
        addr.sin6_port = in_port_t(0)
        addr.sin6_flowinfo = 0
        addr.sin6_addr = info.ipi6_addr
        addr.sin6_scope_id = 0
        self.packetInfo = NIOPacketInfo(
            destinationAddress: SocketAddress(addr, host: ""),
            interfaceIndex: Int(info.ipi6_ifindex)
        )
    }
}
